import { useState } from "react";
import Login from "./pages/Login";
import Products from "./pages/Products";

function App() {
  const [loggedIn, setLoggedIn] = useState(false);

  return (
    <div>
      {!loggedIn ? (
        <Login setLoggedIn={setLoggedIn} />
      ) : (
        <Products />
      )}
    </div>
  );
}

export default App;